glass main() -> Int {
  pour("hello");
  return 0;
}

glass main() -> Int {
  pour(42);
  return 0;
}

glass main() -> Int {
  pour(3.14);
  return 0;
}

glass main() -> Int {
  pour(parched);
  return 0;
}

glass main() -> Int {
  pour(quenched);
  return 0;
}

glass main() -> Int {
  pour(empty);
  return 0;
}

glass main() -> Int {
  drink x: Int = 10;
  pour(x);
  return 0;
}

glass main() -> Int {
  drink mut x: Int = 1;
  x = 2;
  pour(x);
  return 0;
}

glass main() -> Int {
  drink s: String = "thirsty";
  pour(s);
  return 0;
}

glass main() -> Int {
  pour(1 + 2);
  return 0;
}

glass main() -> Int {
  pour(10 - 3);
  return 0;
}

glass main() -> Int {
  pour(4 * 5);
  return 0;
}

glass main() -> Int {
  pour(10 / 2);
  return 0;
}

glass main() -> Int {
  pour(7 % 3);
  return 0;
}

glass main() -> Int {
  thirsty (parched) {
    pour("yes");
  }
  return 0;
}

glass main() -> Int {
  thirsty (quenched) {
    pour("yes");
  } hydrated {
    pour("no");
  }
  return 0;
}

glass main() -> Int {
  drink x: Int = 5;
  thirsty (x > 3) {
    pour("big");
  } hydrated {
    pour("small");
  }
  return 0;
}

glass main() -> Int {
  drink mut i: Int = 0;
  refill 3 times {
    drip i;
  }
  pour(i);
  return 0;
}

glass add(a: Int, b: Int) -> Int {
  return a + b;
}
glass main() -> Int {
  pour(add(3, 4));
  return 0;
}

glass main() -> Int {
  drink a: String = "hello";
  drink b: String = " world";
  pour(a + b);
  return 0;
}

glass main() -> Int {
  pour(1 == 1);
  return 0;
}

glass main() -> Int {
  pour(1 != 2);
  return 0;
}

glass main() -> Int {
  pour(3 < 5);
  return 0;
}

glass main() -> Int {
  pour(5 > 3);
  return 0;
}

glass main() -> Int {
  pour(parched and parched);
  return 0;
}

glass main() -> Int {
  pour(quenched or parched);
  return 0;
}

glass main() -> Int {
  pour(!quenched);
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3];
  pour(size(xs));
  return 0;
}

glass main() -> Int {
  drink mut xs: Reservoir[Int] = [];
  push(xs, 42);
  pour(size(xs));
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [10, 20, 30];
  pour(get(xs, 1));
  return 0;
}

glass double(x: Int) -> Int {
  return x * 2;
}
glass main() -> Int {
  pour(5 |> double);
  return 0;
}

glass main() -> Int {
  spillage {
    throw "oops";
  } cleanup (e: Error) {
    pour("caught");
  }
  return 0;
}

glass main() -> Int {
  spillage {
    throw "x";
  } cleanup (e: Error) {
    pour("cleanup");
  } finally {
    pour("finally");
  }
  return 0;
}

glass fact(n: Int) -> Int {
  thirsty (n <= 1) {
    return 1;
  }
  return n * fact(n - 1);
}
glass main() -> Int {
  pour(fact(5));
  return 0;
}

glass main() -> Int {
  drink mut x: Int = 0;
  drip x;
  drip x;
  pour(x);
  return 0;
}

module test
mode core

glass main() -> Int {
  pour("ok");
  return 0;
}

glass inc(x: Int) -> Int { return x + 1; }
glass dbl(x: Int) -> Int { return x * 2; }
glass main() -> Int {
  pour(inc(dbl(3)));
  return 0;
}

glass main() -> Int {
  pour(-5);
  return 0;
}

glass main() -> Int {
  pour(length("hello"));
  return 0;
}

glass main() -> Int {
  pour(contains("hello world", "world"));
  return 0;
}
